module median_filter_3x3(  
    input [2:0] in00,  
    input [2:0] in01,  
    input [2:0] in02,  
    input [2:0] in10,  
    input [2:0] in11,  
    input [2:0] in12,  
    input [2:0] in20,  
    input [2:0] in21,  
    input [2:0] in22,  
    output reg [2:0] median  
);  

reg [2:0] obf_values [0:8];  
integer i, j;  

always @(*) begin  
    // Collect all inputs into an array  
    obf_values[0] = in00;  
    obf_values[1] = in01;  
    obf_values[2] = in02;  
    obf_values[3] = in10;  
    obf_values[4] = in11;  
    obf_values[5] = in12;  
    obf_values[6] = in20;  
    obf_values[7] = in21;  
    obf_values[8] = in22;  

    // Sort the obf_values  
    for (i = 0; i < 9; i = i + 1) begin  
        for (j = i + 1; j < 9; j = j + 1) begin  
            if (obf_values[i] > obf_values[j]) begin  
                {obf_values[i], obf_values[j]} = {obf_values[j], obf_values[i]};  
            end  
        end  
    end  

    // The median is the 5th element in the sorted array  
    median = obf_values[4];  
end  
endmodule
